import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './nutrition-edit/nutrition-edit.component.js';
import type { NutritionEdit } from './nutrition-edit/nutrition-edit.component.js';
import type { NutritionEntry } from '@motivation/shared';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../_shared/screen-status.js';

export class HealthNutritionEditScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private idValue: string | null = null;
    private contentRoot: HTMLElement | null = null;
    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    set entryId(value: string | null) {
        this.idValue = value;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Edit food', 'health', '/health');
        this.contentRoot = page.content;

        this.statusNodes.loadingNode.textContent = 'Loading entry…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.loadEntry(); });
        this.contentRoot.append(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);

        void this.loadEntry();
    }

    private async loadEntry(): Promise<void> {
        if (!this.idValue || !this.contentRoot) return;
        this.setLoading();
        try {
            const entry = await HealthService.fetchNutritionEntry(this.idValue);
            if (!entry) {
                this.showError(`Entry ${this.idValue} not found.`);
                return;
            }
            this.renderEditor(entry);
        } catch (err) {
            console.error('Failed to load nutrition entry', err);
            this.showError(err instanceof Error ? err.message : 'Failed to load entry.');
        }
    }

    private renderEditor(entry: NutritionEntry): void {
        if (!this.contentRoot) return;
        this.clearStatus();

        const editor = document.createElement('nutrition-edit') as NutritionEdit;
        editor.entry = entry;

        editor.onSave = async (id, updates) => {
            try {
                await HealthService.updateNutritionEntry(id, updates);
                this.returnToDay(updates.date ?? entry.date);
            } catch (err) {
                console.error('Failed to update nutrition entry', err);
                this.showError(err instanceof Error ? err.message : 'Failed to save.');
            }
        };

        editor.onDelete = async (id) => {
            try {
                await HealthService.deleteNutritionEntry(id);
                this.returnToDay(entry.date);
            } catch (err) {
                console.error('Failed to delete nutrition entry', err);
                this.showError(err instanceof Error ? err.message : 'Failed to delete.');
            }
        };

        this.contentRoot.appendChild(editor);
    }

    private returnToDay(date: string): void {
        navigate(`/health/day/${encodeURIComponent(date)}`, { history: 'replace' });
    }

    private showError(message: string): void {
        this.setError(new Error(message));
    }
}

customElements.define('health-nutrition-edit-screen', HealthNutritionEditScreen);
